 &lt;/note&gt;
&quot; pp = pprint.PrettyPrinter(indent=4) pp.pprint(json.dumps(xmltodict.parse(xml_content))) ('{&quot;note&quot;: {&quot;to&quot;: &quot;Tove&quot;, &quot;from&quot;: &quot;Jani&quot;, &quot;heading&quot;: &quot;Reminder&quot;, &quot;body&quot;: ' '&quot;Don't forget me this weekend!&quot;}}') dict = xmltodict.parse(xml_content)dict OrderedDict([('note', OrderedDict([('to', 'Tove'), ('from', 'Jani'), ('heading', 'Reminder'), ('body', &quot;Don't forget me this weekend!&quot;)]))]) dict[&#39;note&#39;] OrderedDict([('to', 'Tove'), ('from', 'Jani'), ('heading', 'Reminder'), ('body', &quot;Don't forget me this weekend!

